    if (trimmed.length === 0) {
        return {accepted: false, reason: 'Request is empty — type what to build.'}
    }

    if (trimmed.length > MAX_REQUEST_LENGTH) {
        return {accepted: false, reason: `Request is too long (max ${MAX_REQUEST_LENGTH} characters).`}
    }

